/* Inline StatusBadge removed in favor of central component */

const TABS = [
  'Overview',
  'Grand Total',
  'Files',
  'RFIs',
  'Submittals',
  'Documents',
  'Vendors',
  'Financials & Admin',
  'Gallery',
];

const mapTabToKey = (tab) => {
  if (tab === 'Grand Total') return 'tables';
  if (tab === 'Financials & Admin') return 'financials';
  return tab.toLowerCase();
};

const formatDetailDate = (value) => {
  if (!value) return 'N/A';
  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return 'N/A';
  return new Intl.DateTimeFormat('en-US', {
    month: '2-digit',
    day: '2-digit',
    year: 'numeric',
  }).format(date);
};

const formatTimestamp = (ts) => {
  if (!ts) return '';
  const d = new Date(ts);
  const hours = d.getHours();
  const mins = d.getMinutes().toString().padStart(2, '0');
  const ampm = hours >= 12 ? 'PM' : 'AM';
  const h = hours % 12 || 12;
  const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];
  return `${h.toString().padStart(2, '0')}:${mins} ${ampm}, ${d.getDate().toString().padStart(2, '0')} ${months[d.getMonth()]} ${d.getFullYear()}`;
};

const getFileUrl = (url) => {
  if (!url) return '';
  if (url.startsWith('http')) return url;
  return `${import.meta.env.VITE_API_URL || 'http://localhost:5000'}/uploads/submittal-files/${url}`;
};

function SubmittalsPage({ hideTopTabs = false, bidId: propBidId, isCompleted = false }) {
  const { id } = useParams();
  const navigate = useNavigate();
  const searchParams = new URLSearchParams(window.location.search);
  const queryBidId = searchParams.get('bid');
  const bidId = parseInt(propBidId || id || queryBidId, 10);

  const [activeTab, setActiveTab] = useState('Submittals');
  const [project, setProject] = useState(null);
  const [submittals, setSubmittals] = useState([]);
  const [statusCounts, setStatusCounts] = useState({ total: 0, draft: 0, open: 0, submitted: 0, under_review: 0, responded: 0, approved: 0, rejected: 0, closed: 0, need_revision: 0 });
  const [loading, setLoading] = useState(false);
  const [showAddModal, setShowAddModal] = useState(false);
  const [deleteModalState, setDeleteModalState] = useState({ isOpen: false, id: null });

  // Filtering
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState('All Items');
  const [showFilterDropdown, setShowFilterDropdown] = useState(false);

  // Pagination
  const [currentPage, setCurrentPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [totalRecords, setTotalRecords] = useState(0);
  const rowsPerPage = 8;
  const [expandedRow, setExpandedRow] = useState(null);

  const fetchSubmittals = async () => {
    if (!bidId) return;
    try {
      setLoading(true);
      const res = await getBidSubmittals(bidId, currentPage, rowsPerPage, searchQuery, statusFilter === 'All Items' ? 'all' : statusFilter.toLowerCase().replace(/\s+/g, '_'));
      if (res && res.success) {
        setSubmittals(res.submittals || (res.data && res.data.submittals) || []);
        setStatusCounts(res.statusCounts || (res.data && res.data.statusCounts) || { total: 0, draft: 0, open: 0, submitted: 0, under_review: 0, responded: 0, approved: 0, rejected: 0, closed: 0, need_revision: 0 });
        setTotalPages(res.totalPages || (res.data && res.data.totalPages) || 1);
        setTotalRecords(res.totalRecords || (res.data && res.data.totalRecords) || 0);
      }
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const fetchProject = async () => {
    if (!bidId) return;
    try {
      const res = await getBid(bidId);
      if (res?.success) {
        setProject(res.bid || res.data?.bid || null);
      }
    } catch (err) {
      console.error(err);
    }
  };

  useEffect(() => {
    fetchSubmittals();
  }, [bidId, currentPage, searchQuery, statusFilter]);

  useEffect(() => {
    fetchProject();
  }, [bidId]);

  const handleStatusChange = async (submittalId, newStatus) => {
    try {
      await updateBidSubmittal(bidId, submittalId, { status: newStatus });
      fetchSubmittals();
    } catch (err) {
      console.error(err);
      alert('Error updating status');
    }
  };

  const handleDeleteClick = (id) => {
    setDeleteModalState({ isOpen: true, id });
  };

  const confirmDelete = async () => {
    const { id } = deleteModalState;
    if (!id) return;
    try {
      await deleteBidSubmittal(bidId, id);
      setDeleteModalState({ isOpen: false, id: null });
      fetchSubmittals();
    } catch (err) {
      console.error(err);
      alert('Error deleting Submittal');
    }
  };

  const handleTabChange = (tab) => {
    setActiveTab(tab);
    const tabKey = mapTabToKey(tab);
    navigate(`/dashboard/projects?bid=${bidId}&tab=${tabKey}`);
  };

  const handleNextPage = () => { if (currentPage < totalPages) setCurrentPage(c => c + 1); };
  const handlePrevPage = () => { if (currentPage > 1) setCurrentPage(c => c - 1); };

  const total = statusCounts.total || totalRecords;
  const open = statusCounts.open || 0;
  const closed = statusCounts.closed || 0;
  const needRevision = statusCounts.need_revision || 0;

  return (
    <>
      {!hideTopTabs && <TopTabs tabs={TABS} activeTab={activeTab} onChange={handleTabChange} />}

      <div className={styles.pageWrapper}>

        <div className={styles.projectHeader}>
          <div className={styles.headerLeft}>
            <h1 className={styles.projectName}>{project?.project_name || 'Submittals Overview'}</h1>
            <p className={styles.projectSubtitle}>{project?.bid_project_id || project?.bid_sales_id || (bidId ? `225-${bidId.toString().padStart(3, '0')}` : '225-048')}</p>
          </div>
        </div>

        <div className={styles.statsContainer}>
          <StatCard title="Total" count={total} totalCount={total} />
          <StatCard title="Open" count={open} totalCount={total} />
          <StatCard title="Need Revision" count={needRevision} totalCount={total} />
          <StatCard title="Closed" count={closed} totalCount={total} />
        </div>

        <div className={styles.listContainer}>

          <div className={styles.tableToolbar}>
            <div className={styles.toolbarLeft}>
              <div className={styles.searchBox}>
                <SearchIcon />
                <input
                  type="text"
                  placeholder="Search"
                  value={searchQuery}
                  onChange={(e) => { setSearchQuery(e.target.value); setCurrentPage(1); }}
                />
              </div>
              <div className={styles.filterWrapper}>
                <button
                  type="button"
                  className={styles.filterBtn}
                  onClick={() => setShowFilterDropdown(!showFilterDropdown)}
                >
                  <FilterIcon />
                  {statusFilter}
                  <ChevronDownIcon />
                </button>
                {showFilterDropdown && (
                  <div className={styles.filterDropdown}>
                    {['All Items', 'Draft', 'Open', 'Submitted', 'Under Review', 'Responded', 'Need Revision', 'Approved', 'Rejected', 'Closed'].map((opt) => (
                      <div
                        key={opt}
                        className={styles.filterOption}
                        onClick={() => { setStatusFilter(opt); setShowFilterDropdown(false); setCurrentPage(1); }}
                      >
                        {opt}
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
            <div className={styles.toolbarRight}>
              {!isCompleted && (
                <button
                  type="button"
                  className={styles.addNewBtn}
                  onClick={() => setShowAddModal(true)}
                >
                  Add New
                </button>
              )}
            </div>
          </div>

          <div className={styles.tableWrapper}>
            <table className={styles.rfiTable}>
              <thead>
                <tr>
                  <th>Number</th>
                  <th>Title</th>
                  <th>Type</th>
                  <th>Due Date</th>
                  <th>Status <SortArrowsIcon /></th>
                  <th>Ball in Court <SortArrowsIcon /></th>
                  <th>Action</th>
                </tr>
              </thead>
              <tbody>
                {loading && submittals.length === 0 ? (
                  <tr><td colSpan="7" style={{ textAlign: 'center', padding: 20 }}>Loading...</td></tr>
                ) : submittals.length === 0 ? (
                  <tr><td colSpan="7" style={{ textAlign: 'center', padding: 20 }}>No Submittals found.</td></tr>
                ) : (
                  submittals.map((item, idx) => {
                    const absoluteIndex = (currentPage - 1) * rowsPerPage + idx + 1;
                    const isExpanded = expandedRow === item.id;
                    const history = item.versions || [];

                    return (
                      <React.Fragment key={item.id}>
                        <tr
                          className={isExpanded ? styles.expandedRowParent : ''}
                          style={{ cursor: 'pointer' }}
                          onClick={() => setExpandedRow(isExpanded ? null : item.id)}
                        >
                          <td className={styles.srNoCell}>
                            <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                              {item.priority === 'High' && (
                                <div style={{ alignSelf: 'flex-start', background: '#475467', color: '#fff', fontSize: 10, padding: '2px 6px', borderRadius: 4, whiteSpace: 'nowrap' }}>
                                  Priority - High
                                </div>
                              )}
                              <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                                <WarningIcon />
                                <span>S. {7566 + absoluteIndex}</span>
                              </div>
                            </div>
                          </td>
                          <td className={styles.titleCell}>
                            <span className={styles.rfiTitle}>{item.title}</span>
                          </td>
                          <td className={styles.notesCell} style={{ color: '#475467' }}>{item.type || 'Shop Drawing'}</td>
                          <td className={styles.notesCell} style={{ color: '#475467' }}>{formatDetailDate(item.due_date)}</td>
                          <td className={styles.statusCell}>
                            <StatusBadge
                              status={item.status}
                              onStatusChange={(newStatus) => handleStatusChange(item.id, newStatus)}
                              statusOptions={['draft', 'open', 'submitted', 'under_review', 'responded', 'need_revision', 'approved', 'rejected', 'closed']}
                            />
                          </td>
                          <td className={styles.ballCell}>
                            <div className={styles.ballCompany}>{item.ball_in_court || 'N/A'}</div>
                          </td>
                          <td className={styles.actionCell}>
                            <div className={styles.actionIcons} onClick={e => e.stopPropagation()}>
                              <button className={styles.iconBtn} title="View" onClick={() => navigate(`/dashboard/projects/${bidId}/submittals/${item.id}`)}><EyeIcon /></button>
                              <button
                                className={styles.iconBtn}
                                title="Download"
                                disabled={!history.some((entry) => entry.file_url)}
                                onClick={() => {
                                  const fileEntry = history.find((entry) => entry.file_url);
                                  if (fileEntry) window.open(getFileUrl(fileEntry.file_url), '_blank', 'noopener,noreferrer');
                                }}
                              >
                                <DownloadIcon />
                              </button>
                              {!isCompleted && (
                                <button className={styles.iconBtn} title="Delete" onClick={() => handleDeleteClick(item.id)}><TrashIcon /></button>
                              )}
                            </div>
                          </td>
                        </tr>

                        {/* Expanded History row */}
                        {isExpanded && (
                          <tr className={styles.expandedRowChild}>
                            <td colSpan="7" style={{ padding: 0 }}>
                              <div className={styles.historyWrapper}>
                                <div style={{ padding: '0 32px 16px', color: '#475467', fontSize: 14 }}>
                                  {item.description || 'Lorem ipsum dolor sit amet, consectetur adipiscing elit, sed do eiusmod tempor incididunt ut labore et dolore magna aliqua.'}
                                </div>
                                {history.length > 0 ? history.map((entry) => (
                                  <div key={entry.id} className={styles.historyCard} style={{ flexDirection: 'column' }}>
                                    <div style={{ display: 'flex', width: '100%', justifyContent: 'space-between' }}>
                                      <div className={styles.historyInfo}>
                                        <div className={styles.personHeader}>
                                          <span className={styles.dotOnline} />
                                          <div className={styles.personNameGroup}>
                                            <span className={styles.personName}>{entry.created_by_name || 'Unknown'}</span>
                                            <div className={styles.personCompany}>{entry.company || 'Aquil Tech Labs'}</div>
                                          </div>
                                        </div>
                                        <p className={styles.historyMessage}>{entry.message}</p>
                                        <span className={styles.historyTime}>{formatTimestamp(entry.created_at)}</span>
                                      </div>
                                      <div className={styles.historyRight}>
                                        <StatusBadge status={entry.status} />
                                        {entry.file_url && (
                                          <div className={styles.submittalHistoryPdf}>
                                            <div className={styles.pdfIconBox}>
                                              <a href={getFileUrl(entry.file_url)} target="_blank" rel="noopener noreferrer">
                                                <PdfDocIcon />
                                              </a>
                                            </div>
                                            <div className={styles.pdfActions}>
                                              <EyeIcon />
                                              <ShareIcon />
                                            </div>
                                            <span className={styles.pdfVersion}>Version - {entry.version || 1}</span>
                                          </div>
                                        )}
                                      </div>
                                    </div>
                                    <div className={styles.replyActionRow}>
                                      <button className={styles.viewReplyBtn}>
                                        <ChevronDownIcon /> View Reply
                                      </button>
                                    </div>
                                  </div>
                                )) : (
                                  <div style={{ padding: '20px 32px', color: '#667085' }}>No history entries yet.</div>
                                )}
                                <div style={{ textAlign: 'center' }}>
                                  <button className={styles.viewMoreBtn} onClick={() => navigate(`/dashboard/projects/${bidId}/submittals/${item.id}`)}>
                                    View More
                                  </button>
                                </div>
                              </div>
                            </td>
                          </tr>
                        )}
                      </React.Fragment>
                    );
                  })
                )}
              </tbody>
            </table>
          </div>

          {/* Pagination */}
          <div className={styles.paginationArea}>
            <button
              className={styles.pageBtn}
              onClick={handlePrevPage}
              disabled={currentPage === 1 || submittals.length === 0}
            >
              Previous
            </button>
            <span className={styles.pageInfo}>
              Page {submittals.length > 0 ? currentPage : 0} of {totalPages}
            </span>
            <button
              className={styles.pageBtn}
              onClick={handleNextPage}
              disabled={currentPage === totalPages || submittals.length === 0}
            >
              Next
            </button>
          </div>
        </div>

        {deleteModalState.isOpen && (
          <DeleteConfirmModal
            isOpen={deleteModalState.isOpen}
            onClose={() => setDeleteModalState({ isOpen: false, id: null })}
            onConfirm={confirmDelete}
            itemName="this Submittal"
          />
        )}

        {showAddModal && (
          <AddSubmittalModal
            isOpen={showAddModal}
            onClose={() => setShowAddModal(false)}
            bidId={bidId}
            onCreated={fetchSubmittals}
          />
        )}
      </div>
    </>
  );
}

export default SubmittalsPage;
